CREATE TYPE "Role" AS ENUM ('ADMIN','ENTERPRISE_ARCHITECT','SOLUTION_ARCHITECT','CLOUD_ARCHITECT','REVIEWER','STAKEHOLDER');
CREATE TYPE "ProjectStatus" AS ENUM ('DRAFT','DISCOVERY_IN_PROGRESS','MODEL_READY','GENERATING','ARTIFACTS_READY','ARCHIVED');
CREATE TYPE "ArtifactType" AS ENUM ('EXECUTIVE_SUMMARY','CURRENT_STATE_ASSESSMENT','TARGET_ARCHITECTURE','C4_CONTEXT_DIAGRAM','C4_CONTAINER_DIAGRAM','AZURE_ARCHITECTURE_DIAGRAM','NETWORK_DIAGRAM','ADR','TERRAFORM','BICEP','KUBERNETES_MANIFEST','HELM_CHART','AZURE_DEVOPS_PIPELINE','GITHUB_ACTIONS_PIPELINE','SECURITY_REVIEW','RISK_ASSESSMENT','COST_ESTIMATE','IMPLEMENTATION_ROADMAP','EXECUTIVE_PRESENTATION');
CREATE TYPE "ArtifactStatus" AS ENUM ('DRAFT','GENERATING','READY','FAILED');
CREATE TYPE "JobStatus" AS ENUM ('QUEUED','RUNNING','COMPLETED','FAILED');
CREATE TABLE "Organization" ("id" TEXT PRIMARY KEY,"name" TEXT NOT NULL,"industry" TEXT,"plan" TEXT NOT NULL DEFAULT 'ENTERPRISE',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "User" ("id" TEXT PRIMARY KEY,"email" TEXT NOT NULL UNIQUE,"displayName" TEXT NOT NULL,"passwordHash" TEXT NOT NULL,"role" "Role" NOT NULL DEFAULT 'SOLUTION_ARCHITECT',"organizationId" TEXT NOT NULL REFERENCES "Organization"("id"),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "RefreshToken" ("id" TEXT PRIMARY KEY,"userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"tokenHash" TEXT NOT NULL,"revokedAt" TIMESTAMP(3),"expiresAt" TIMESTAMP(3) NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Project" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL REFERENCES "Organization"("id"),"ownerId" TEXT NOT NULL REFERENCES "User"("id"),"name" TEXT NOT NULL,"description" TEXT,"cloudProvider" TEXT,"migrationType" TEXT,"currentStateSummary" TEXT,"targetStateSummary" TEXT,"status" "ProjectStatus" NOT NULL DEFAULT 'DRAFT',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX "Project_organizationId_idx" ON "Project"("organizationId");
CREATE TABLE "DiscoveryAnswer" ("id" TEXT PRIMARY KEY,"projectId" TEXT NOT NULL REFERENCES "Project"("id") ON DELETE CASCADE,"question" TEXT NOT NULL,"answer" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "ArchitectureModel" ("id" TEXT PRIMARY KEY,"projectId" TEXT NOT NULL REFERENCES "Project"("id") ON DELETE CASCADE,"version" INTEGER NOT NULL,"businessContext" JSONB NOT NULL,"currentState" JSONB NOT NULL,"targetState" JSONB NOT NULL,"applications" JSONB NOT NULL,"integrations" JSONB NOT NULL,"dataStores" JSONB NOT NULL,"infrastructure" JSONB NOT NULL,"security" JSONB NOT NULL,"deployment" JSONB NOT NULL,"operations" JSONB NOT NULL,"assumptions" JSONB NOT NULL,"constraints" JSONB NOT NULL,"decisions" JSONB NOT NULL,"risks" JSONB NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE("projectId","version"));
CREATE TABLE "Artifact" ("id" TEXT PRIMARY KEY,"projectId" TEXT NOT NULL REFERENCES "Project"("id") ON DELETE CASCADE,"architectureModelId" TEXT NOT NULL REFERENCES "ArchitectureModel"("id"),"type" "ArtifactType" NOT NULL,"title" TEXT NOT NULL,"format" TEXT NOT NULL,"content" JSONB NOT NULL,"status" "ArtifactStatus" NOT NULL DEFAULT 'DRAFT',"version" INTEGER NOT NULL DEFAULT 1,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX "Artifact_projectId_type_idx" ON "Artifact"("projectId","type");
CREATE TABLE "Adr" ("id" TEXT PRIMARY KEY,"projectId" TEXT NOT NULL REFERENCES "Project"("id") ON DELETE CASCADE,"architectureModelId" TEXT NOT NULL REFERENCES "ArchitectureModel"("id"),"number" INTEGER NOT NULL,"title" TEXT NOT NULL,"status" TEXT NOT NULL,"context" TEXT NOT NULL,"decision" TEXT NOT NULL,"alternatives" JSONB NOT NULL,"consequences" JSONB NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE("projectId","number"));
CREATE TABLE "GenerationJob" ("id" TEXT PRIMARY KEY,"projectId" TEXT NOT NULL REFERENCES "Project"("id") ON DELETE CASCADE,"requestedBy" TEXT NOT NULL,"jobType" TEXT NOT NULL,"status" "JobStatus" NOT NULL DEFAULT 'QUEUED',"error" TEXT,"startedAt" TIMESTAMP(3),"completedAt" TIMESTAMP(3));
CREATE TABLE "AiRun" ("id" TEXT PRIMARY KEY,"projectId" TEXT,"promptType" TEXT NOT NULL,"promptInput" JSONB NOT NULL,"generatedOutput" JSONB,"modelName" TEXT NOT NULL,"tokenUsage" JSONB,"status" TEXT NOT NULL,"error" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "AuditLog" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL REFERENCES "Organization"("id"),"userId" TEXT REFERENCES "User"("id"),"action" TEXT NOT NULL,"entityType" TEXT NOT NULL,"entityId" TEXT,"metadata" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
